"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Button } from "@/shared/components/ui/button";
import { useTranslations, useLocale } from "@/shared/providers/i18n-provider";
import { Telescope, Home } from "lucide-react";

export default function ProductNotFound() {
  const t = useTranslations();
  const locale = useLocale();

  return (
    <div className="min-h-[80vh] flex flex-col items-center justify-center text-center px-6 relative overflow-hidden">
      {/* Background Decorative Elements */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full max-w-4xl bg-[radial-gradient(circle,rgba(98,87,244,0.1)_0%,transparent_70%)] pointer-events-none" />

      <div className="relative z-10 space-y-8 max-w-2xl">
        <div className="relative inline-block">
          <div className="absolute inset-0 blur-2xl bg-primary/20 rounded-full" />
          <Telescope size={120} className="text-primary relative animate-bounce" />
        </div>

        <div className="space-y-4">
          <h1 className="text-4xl md:text-5xl font-bold text-text-main">
            {t.product_detail.not_found_title}
          </h1>
          <p className="text-lg text-text-soft">
            {t.product_detail.not_found_desc}
          </p>
        </div>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4 pt-4">
          <Button asChild size="lg" className="rounded-full px-8 h-14">
            <Link href={`/${locale}/catalogo`}>
              {t.product_detail.not_found_cta}
            </Link>
          </Button>
          <Button asChild variant="ghost" size="lg" className="rounded-full px-8 h-14 text-text-muted hover:text-text-main">
            <Link href={`/${locale}`}>
              <Home size={20} className="mr-2" />
              {t.navbar.home}
            </Link>
          </Button>
        </div>
      </div>

      {/* Atmospheric Star Field Effect */}
      <div className="absolute inset-0 pointer-events-none opacity-40">
        <StarFieldInner count={20} />
      </div>
    </div>
  );
}


function StarFieldInner({ count }: { count: number }) {
  const [mounted, setMounted] = useState(false);
  const [starData, setStarData] = useState<{
    width: string;
    height: string;
    top: string;
    left: string;
    delay: string;
    duration: string;
  }[]>([]);

  useEffect(() => {
    setMounted(true);
  }, []);

  const starData = useMemo(() => {
    if (!mounted) return [];
    return [...Array(count)].map(() => ({
      width: Math.random() * 3 + "px",
      height: Math.random() * 3 + "px",
      top: Math.random() * 100 + "%",
      left: Math.random() * 100 + "%",
      delay: Math.random() * 5 + "s",
      duration: Math.random() * 3 + 2 + "s"
    }));
  }, [mounted, count]);

  if (!mounted) return null;

  return (
    <>
      {starData.map((star, i) => (
        <div 
          key={i}
          className="absolute bg-white rounded-full animate-pulse"
          style={{
            width: star.width,
            height: star.height,
            top: star.top,
            left: star.left,
            animationDelay: star.delay,
            animationDuration: star.duration
          }}
        />
      ))}
    </>
  );
}

import { Metadata } from "next";
import { getDictionary } from "@/lib/i18n";
import { ConfirmationView } from "../../../../features/checkout/components/ConfirmationView";

export async function generateMetadata({ params }: { params: Promise<{ locale: string }> }): Promise<Metadata> {
  const { locale } = await params;
  const dict = await getDictionary(locale);
  const t = dict.checkout;

  return {
    title: `${t.order_received} | AstroAssist AI`,
    description: t.success_desc,
  };
}

interface ConfirmationPageProps {
  params: Promise<{
    locale: string;
  }>;
  searchParams: Promise<{
    orderId?: string;
  }>;
}

export default async function ConfirmationPage({ params, searchParams }: ConfirmationPageProps) {
  const { orderId } = await searchParams;

  return (
    <div className="container-max mx-auto pt-32 pb-20 px-6">
      <ConfirmationView orderId={orderId} />
    </div>
  );
}

'use client';

import React, { useState, useTransition } from 'react';
import { useAdminUsers } from '../hooks/useAdminUsers';
import { UsersTable } from './UsersTable';
import { CreateCustomerDialog } from './CreateCustomerDialog';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import { Search, Users, AlertCircle, RefreshCw } from 'lucide-react';

/**
 * Página principal de gestión de clientes para el panel admin.
 * Implementa TanStack Query para el estado del servidor y evita efectos secundarios manuales.
 */
export const AdminUsersPage: React.FC = () => {
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState('');
  const [searchInput, setSearchInput] = useState('');
  const [isPending, startTransition] = useTransition();

  const {
    users,
    meta,
    isLoading,
    isError,
    error,
    refetch,
    createCustomer,
    updateCustomer,
    toggleStatus,
  } = useAdminUsers({
    page,
    limit: 10,
    search: search.trim() || undefined,
  });

  // Manejo de búsqueda con transición para no bloquear el UI
  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value;
    setSearchInput(value);

    startTransition(() => {
      setSearch(value);
      setPage(1);
    });
  };

  return (
    <div className="space-y-6">
      {/* ── Header ── */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-blue-500/10 rounded-xl border border-blue-500/20">
            <Users className="w-5 h-5 text-blue-400" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white">Gestión de Clientes</h1>
            <p className="text-sm text-zinc-500">
              {isLoading ? 'Cargando...' : meta ? `${meta.total} clientes registrados` : '—'}
            </p>
          </div>
        </div>
        <CreateCustomerDialog onCreateCustomer={async (payload) => { await createCustomer(payload); }} />
      </div>

      {/* ── Search + Refresh ── */}
      <div className="flex gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
          <Input
            id="admin-search-users"
            placeholder="Buscar por nombre, email o cédula..."
            value={searchInput}
            onChange={handleSearch}
            className="pl-10 bg-white/3 border-white/6 text-white placeholder:text-zinc-600"
          />
        </div>
        <Button
          variant="outline"
          onClick={() => refetch()}
          disabled={isLoading}
          className="border-white/6 text-zinc-400 hover:text-white hover:bg-white/5 shrink-0"
          aria-label="Refrescar lista"
        >
          <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
        </Button>
      </div>

      {/* ── Error Global ── */}
      {isError && (
        <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 flex items-start gap-3 text-sm text-red-400">
          <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
          <p>
            {error instanceof Error 
              ? error.message 
              : (error as unknown as { response?: { data?: { message?: string } } })?.response?.data?.message || 'Error al cargar los usuarios'}
          </p>
        </div>
      )}

      {/* ── Tabla ── */}
      <UsersTable
        users={users}
        meta={meta}
        isLoading={isLoading}
        page={page}
        onPageChange={setPage}
        onToggleStatus={async (id, isActive) => { await toggleStatus({ id, isActive }); }}
        onUpdate={async (id, payload) => {
          try {
            await updateCustomer({ id, payload });
            return { success: true };
          } catch (err: unknown) {
            return { 
              success: false, 
              error: (err as unknown as { response?: { data?: { message?: string } } })?.response?.data?.message || 'Error al actualizar el cliente' 
            };
          }
        }}
      />
    </div>
  );
};

'use client';

import React from 'react';
import { useForm, useWatch, UseFormReturn } from 'react-hook-form';
import { classValidatorResolver } from '@hookform/resolvers/class-validator';
import { CreateCustomerDto } from '../schemas/create-customer.schema';
import { useGeo } from '@/features/auth/hooks/useGeo';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import { Label } from '@/shared/components/ui/label';
import { Combobox } from '@/shared/components/ui/combobox';
import {
  Mail,
  Lock,
  Loader2,
  AlertCircle,
  ChevronRight,
  ChevronLeft,
  CheckCircle2,
  Calendar,
  Phone,
  User,
  UserPlus,
} from 'lucide-react';

interface CreateCustomerFormProps {
  onSubmit: (data: CreateCustomerDto) => Promise<void>;
  serverError: string | null;
  isSubmitting: boolean;
}

export const CreateCustomerForm: React.FC<CreateCustomerFormProps> = ({
  onSubmit,
  serverError,
  isSubmitting,
}) => {
  const [step, setStep] = React.useState(1);
  const TOTAL_STEPS = 4;

  const {
    provinces,
    cantons,
    districts,
    loadCantons,
    loadDistricts,
    loadingProvinces,
    loadingCantons,
    loadingDistricts,
  } = useGeo();

  const form = useForm<CreateCustomerDto>({
    resolver: classValidatorResolver(CreateCustomerDto),
  });

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    trigger,
    formState: { errors },
  } = form;

  const selectedProvince = useWatch({ control: form.control, name: 'province' });
  const selectedCanton = useWatch({ control: form.control, name: 'canton' });
  const fullNameWatch = useWatch({ control: form.control, name: 'fullName' });
  const cedulaWatch = useWatch({ control: form.control, name: 'cedula' });
  const emailWatch = useWatch({ control: form.control, name: 'email' });
  const districtWatch = useWatch({ control: form.control, name: 'district' });

  const nextStep = async () => {
    type FieldName = keyof CreateCustomerDto;
    let fieldsToValidate: FieldName[] = [];
    if (step === 1) fieldsToValidate = ['cedula', 'fullName', 'birthDate'];
    if (step === 2) fieldsToValidate = ['email', 'phone'];
    if (step === 3) fieldsToValidate = ['province', 'canton', 'district', 'town', 'exactAddress'];

    const isValid = await trigger(fieldsToValidate);
    if (isValid) setStep((s) => s + 1);
  };

  const prevStep = () => setStep((s) => s - 1);

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="mt-4">
      <div className="mb-4">
        <p className="text-xs text-zinc-500 mb-2">
          Paso {step} de {TOTAL_STEPS}
        </p>
        <div className="w-full bg-white/5 h-1 rounded-full overflow-hidden">
          <div
            className="bg-blue-600 h-full transition-all duration-300"
            style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
          />
        </div>
      </div>

      <div className="space-y-4 min-h-[220px]">
        {serverError && (
          <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 flex items-start gap-3 text-sm text-red-400">
            <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
            <p>{serverError}</p>
          </div>
        )}

        {/* Paso 1: Personal */}
        {step === 1 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="admin-cedula" className="text-zinc-300">Cédula</Label>
              <div className="relative">
                <User className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-cedula" placeholder="0-0000-0000" className="pl-10 bg-white/5 border-white/10 text-white" {...register('cedula')} />
              </div>
              {errors.cedula && <p className="text-xs text-red-400">{errors.cedula.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-fullName" className="text-zinc-300">Nombre Completo</Label>
              <Input id="admin-fullName" placeholder="Juan Pérez" className="bg-white/5 border-white/10 text-white" {...register('fullName')} />
              {errors.fullName && <p className="text-xs text-red-400">{errors.fullName.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-birthDate" className="text-zinc-300">Fecha de Nacimiento</Label>
              <div className="relative">
                <Calendar className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-birthDate" type="date" className="pl-10 bg-white/5 border-white/10 text-white" {...register('birthDate')} />
              </div>
              {errors.birthDate && <p className="text-xs text-red-400">{errors.birthDate.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 2: Contacto */}
        {step === 2 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="admin-email" className="text-zinc-300">Correo Electrónico</Label>
              <div className="relative">
                <Mail className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-email" type="email" placeholder="juan@ejemplo.com" className="pl-10 bg-white/5 border-white/10 text-white" {...register('email')} />
              </div>
              {errors.email && <p className="text-xs text-red-400">{errors.email.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-phone" className="text-zinc-300">Teléfono</Label>
              <div className="relative">
                <Phone className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-phone" placeholder="8888-8888" className="pl-10 bg-white/5 border-white/10 text-white" {...register('phone')} />
              </div>
              {errors.phone && <p className="text-xs text-red-400">{errors.phone.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 3: Ubicación */}
        {step === 3 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-2">
                <Label className="text-zinc-300">Provincia</Label>
                <Combobox
                  options={provinces.map((p) => ({ label: p.name, value: p.id }))}
                  value={selectedProvince}
                  onChange={(val) => {
                    setValue('province', val);
                    setValue('canton', '');
                    setValue('district', '');
                    loadCantons(val);
                  }}
                  disabled={loadingProvinces}
                  placeholder="Provincia"
                />
                {errors.province && <p className="text-xs text-red-400">{errors.province.message}</p>}
              </div>
              <div className="space-y-2">
                <Label className="text-zinc-300">Cantón</Label>
                <Combobox
                  options={cantons.map((c) => ({ label: c.name, value: c.id }))}
                  value={selectedCanton}
                  onChange={(val) => {
                    setValue('canton', val);
                    setValue('district', '');
                    loadDistricts(selectedProvince, val);
                  }}
                  disabled={!selectedProvince || loadingCantons}
                  placeholder="Cantón"
                />
                {errors.canton && <p className="text-xs text-red-400">{errors.canton.message}</p>}
              </div>
            </div>
            <div className="space-y-2">
              <Label className="text-zinc-300">Distrito</Label>
              <Combobox
                options={districts.map((d) => ({ label: d.name, value: d.id }))}
                value={districtWatch}
                onChange={(val) => setValue('district', val)}
                disabled={!selectedCanton || loadingDistricts}
                placeholder="Distrito"
              />
              {errors.district && <p className="text-xs text-red-400">{errors.district.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-town" className="text-zinc-300">Localidad / Barrio</Label>
              <Input id="admin-town" placeholder="San José Centro" className="bg-white/5 border-white/10 text-white" {...register('town')} />
              {errors.town && <p className="text-xs text-red-400">{errors.town.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-exactAddress" className="text-zinc-300">Dirección Exacta</Label>
              <Input id="admin-exactAddress" placeholder="Frente a la plaza..." className="bg-white/5 border-white/10 text-white" {...register('exactAddress')} />
              {errors.exactAddress && <p className="text-xs text-red-400">{errors.exactAddress.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 4: Seguridad */}
        {step === 4 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="admin-password" className="text-zinc-300">Contraseña</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-password" type="password" placeholder="••••••••" className="pl-10 bg-white/5 border-white/10 text-white" {...register('password')} />
              </div>
              {errors.password && <p className="text-xs text-red-400">{errors.password.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="admin-confirmPassword" className="text-zinc-300">Confirmar Contraseña</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="admin-confirmPassword" type="password" placeholder="••••••••" className="pl-10 bg-white/5 border-white/10 text-white" {...register('confirmPassword')} />
              </div>
              {errors.confirmPassword && <p className="text-xs text-red-400">{errors.confirmPassword.message}</p>}
            </div>
            <div className="p-4 bg-blue-500/5 border border-blue-500/10 rounded-lg space-y-2">
              <h4 className="text-sm font-medium text-blue-400 flex items-center gap-2">
                <CheckCircle2 className="w-4 h-4" /> Resumen
              </h4>
              <div className="text-xs text-zinc-400 space-y-1">
                <p>Nombre: {fullNameWatch}</p>
                <p>Cédula: {cedulaWatch}</p>
                <p>Correo: {emailWatch}</p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Navegación */}
      <div className="flex justify-between gap-4 mt-6 pt-4 border-t border-white/6">
        {step > 1 ? (
          <Button type="button" variant="outline" onClick={prevStep} className="border-white/10 text-white hover:bg-white/5">
            <ChevronLeft className="w-4 h-4 mr-2" /> Atrás
          </Button>
        ) : (
          <div />
        )}
        {step < TOTAL_STEPS ? (
          <Button type="button" onClick={nextStep} className="bg-blue-600 hover:bg-blue-500">
            Siguiente <ChevronRight className="w-4 h-4 ml-2" />
          </Button>
        ) : (
          <Button type="submit" disabled={isSubmitting} className="bg-blue-600 hover:bg-blue-500 min-w-[140px]">
            {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <UserPlus className="w-4 h-4 mr-2" />}
            {isSubmitting ? 'Creando...' : 'Crear Cliente'}
          </Button>
        )}
      </div>
    </form>
  );
};

'use client';

import React, { useMemo, useState } from 'react';
import {
  useReactTable,
  getCoreRowModel,
  flexRender,
  ColumnDef,
} from '@tanstack/react-table';
import { Badge } from '@/shared/components/ui/badge';
import { Button } from '@/shared/components/ui/button';
import {
  UserCheck,
  UserX,
  Users,
  ChevronLeft,
  ChevronRight,
  Edit2,
} from 'lucide-react';
import type { AdminUser, PaginationMeta } from '../types/admin.types';
import { format } from 'date-fns';
import { EditCustomerDialog } from './EditCustomerDialog';

interface UsersTableProps {
  users: AdminUser[];
  meta?: PaginationMeta;
  isLoading: boolean;
  page: number;
  onPageChange: (page: number) => void;
  onToggleStatus: (id: string, isActive: boolean) => Promise<void>;
  onUpdate: (id: string, data: { fullName?: string; phone?: string }) => Promise<{ success: boolean; error?: string }>;
}

/** Skeleton para la tabla mientras carga */
function TableSkeleton() {
  return (
    <div className="space-y-3">
      {Array.from({ length: 5 }).map((_, i) => (
        <div key={`skeleton-${i}`} className="flex items-center gap-4 p-4 rounded-lg bg-white/2">
          <div className="h-10 w-10 rounded-full bg-white/5 animate-pulse" />
          <div className="flex-1 space-y-2">
            <div className="h-4 w-32 bg-white/5 rounded animate-pulse" />
            <div className="h-3 w-48 bg-white/5 rounded animate-pulse" />
          </div>
          <div className="h-6 w-16 bg-white/5 rounded-full animate-pulse" />
          <div className="h-8 w-20 bg-white/5 rounded animate-pulse" />
        </div>
      ))}
    </div>
  );
}

/** Estado vacío cuando no hay clientes */
function EmptyState() {
  return (
    <div className="flex flex-col items-center justify-center py-16 text-center">
      <div className="p-4 bg-white/3 rounded-2xl border border-white/6 mb-4">
        <Users className="w-10 h-10 text-zinc-500" />
      </div>
      <h3 className="text-lg font-semibold text-zinc-300 mb-1">Sin clientes registrados</h3>
      <p className="text-sm text-zinc-500 max-w-xs">
        Aún no hay clientes en el sistema. Usa el botón &quot;Crear Cliente&quot; para añadir el primero.
      </p>
    </div>
  );
}

export const UsersTable: React.FC<UsersTableProps> = ({
  users,
  meta,
  isLoading,
  page,
  onPageChange,
  onToggleStatus,
  onUpdate,
}) => {
  const [editingUser, setEditingUser] = useState<AdminUser | null>(null);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

  const columns = useMemo<ColumnDef<AdminUser>[]>(
    () => [
      {
        header: 'Cliente',
        accessorKey: 'profile.fullName',
        cell: ({ row }) => (
          <div>
            <p className="font-medium text-zinc-100">{row.original.profile?.fullName ?? '—'}</p>
            <p className="text-xs text-zinc-500">{row.original.email}</p>
          </div>
        ),
      },
      {
        header: 'Cédula',
        accessorKey: 'profile.cedula',
        cell: ({ row }) => (
          <span className="font-mono text-xs text-zinc-300">
            {row.original.profile?.cedula ?? '—'}
          </span>
        ),
      },
      {
        header: 'Estado',
        accessorKey: 'isActive',
        cell: ({ row }) => (
          <Badge
            variant={row.original.isActive ? 'default' : 'destructive'}
            className={
              row.original.isActive
                ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20 hover:bg-emerald-500/15'
                : 'bg-red-500/10 text-red-400 border-red-500/20 hover:bg-red-500/15'
            }
          >
            {row.original.isActive ? 'Activo' : 'Inactivo'}
          </Badge>
        ),
      },
      {
        header: 'Registro',
        accessorKey: 'createdAt',
        cell: ({ row }) => (
          <span className="text-xs text-zinc-400">
            {format(new Date(row.original.createdAt), 'dd/MM/yyyy')}
          </span>
        ),
      },
      {
        id: 'actions',
        header: () => <div className="text-right">Acciones</div>,
        cell: ({ row }) => (
          <div className="flex justify-end gap-1">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => {
                setEditingUser(row.original);
                setIsEditDialogOpen(true);
              }}
              className="text-zinc-400 hover:text-white hover:bg-white/5"
              aria-label={`Editar ${row.original.profile?.fullName}`}
            >
              <Edit2 className="w-4 h-4" />
            </Button>
            <Button
              variant="ghost"
              size="sm"
              onClick={() => onToggleStatus(row.original.id, !row.original.isActive)}
              className="text-zinc-400 hover:text-white hover:bg-white/5"
              aria-label={
                row.original.isActive
                  ? `Desactivar ${row.original.profile?.fullName}`
                  : `Activar ${row.original.profile?.fullName}`
              }
            >
              {row.original.isActive ? <UserX className="w-4 h-4" /> : <UserCheck className="w-4 h-4" />}
            </Button>
          </div>
        ),
      },
    ],
    [onToggleStatus]
  );

  const table = useReactTable({
    data: users,
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  if (isLoading) return <TableSkeleton />;
  if (users.length === 0) return <EmptyState />;

  return (
    <div className="space-y-4">
      {/* ── Tabla Desktop ── */}
      <div className="hidden md:block overflow-hidden rounded-xl border border-white/6 bg-white/2">
        <table className="w-full text-sm text-left">
          <thead>
            {table.getHeaderGroups().map((headerGroup) => (
              <tr key={headerGroup.id} className="border-b border-white/6 bg-white/2">
                {headerGroup.headers.map((header) => (
                  <th
                    key={header.id}
                    className="p-4 text-xs font-medium text-zinc-400 uppercase tracking-wider"
                  >
                    {header.isPlaceholder
                      ? null
                      : flexRender(header.column.columnDef.header, header.getContext())}
                  </th>
                ))}
              </tr>
            ))}
          </thead>
          <tbody className="divide-y divide-white/4">
            {table.getRowModel().rows.map((row) => (
              <tr key={row.id} className="hover:bg-white/2 transition-colors duration-150">
                {row.getVisibleCells().map((cell) => (
                  <td key={cell.id} className="p-4">
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ── Cards Mobile (Se mantiene manual para control UX específico) ── */}
      <div className="md:hidden space-y-3">
        {Array.isArray(users) && users.map((user) => (
          <div key={user.id} className="p-4 rounded-xl bg-white/2 border border-white/6 space-y-3">
            <div className="flex items-start justify-between">
              <div>
                <p className="font-medium text-zinc-100">{user.profile?.fullName ?? '—'}</p>
                <p className="text-xs text-zinc-500">{user.email}</p>
              </div>
              <Badge variant={user.isActive ? 'default' : 'destructive'} className={
                user.isActive 
                  ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20'
                  : 'bg-red-500/10 text-red-400 border-red-500/20'
              }>
                {user.isActive ? 'Activo' : 'Inactivo'}
              </Badge>
            </div>
            <div className="flex items-center justify-between text-xs text-zinc-500">
              <span className="font-mono">{user.profile?.cedula ?? '—'}</span>
              <span>{format(new Date(user.createdAt), 'dd/MM/yyyy')}</span>
            </div>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={() => {
                  setEditingUser(user);
                  setIsEditDialogOpen(true);
                }}
                className="flex-1 border-white/10 text-zinc-300 hover:bg-white/5"
              >
                <Edit2 className="w-3.5 h-3.5 mr-2" /> Editar
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={() => onToggleStatus(user.id, !user.isActive)}
                className="flex-1 border-white/10 text-zinc-300 hover:bg-white/5"
              >
                {user.isActive ? (
                  <><UserX className="w-3.5 h-3.5 mr-2" /> Desactivar</>
                ) : (
                  <><UserCheck className="w-3.5 h-3.5 mr-2" /> Activar</>
                )}
              </Button>
            </div>
          </div>
        ))}
      </div>

      {/* ── Paginación ── */}
      {meta && meta.totalPages > 1 && (
        <div className="flex items-center justify-between pt-2">
          <p className="text-xs text-zinc-500">
            Mostrando {users.length} de {meta.total} clientes
          </p>
          <div className="flex items-center gap-2">
            <Button
              variant="ghost"
              size="sm"
              disabled={page <= 1}
              onClick={() => onPageChange(page - 1)}
              className="text-zinc-400 hover:text-white"
              aria-label="Página anterior"
            >
              <ChevronLeft className="w-4 h-4" />
            </Button>
            <span className="text-xs text-zinc-400 tabular-nums">
              {page} / {meta.totalPages}
            </span>
            <Button
              variant="ghost"
              size="sm"
              disabled={page >= meta.totalPages}
              onClick={() => onPageChange(page + 1)}
              className="text-zinc-400 hover:text-white"
              aria-label="Página siguiente"
            >
              <ChevronRight className="w-4 h-4" />
            </Button>
          </div>
        </div>
      )}

      <EditCustomerDialog
        user={editingUser}
        open={isEditDialogOpen}
        onOpenChange={setIsEditDialogOpen}
        onUpdate={onUpdate}
      />
    </div>
  );
};

'use client';

import React from 'react';
import { useForm, useWatch } from 'react-hook-form';
import { classValidatorResolver } from '@hookform/resolvers/class-validator';
import { RegisterDto } from '@shared/dto/register.dto';
import { useGeo } from '@/features/auth/hooks/useGeo';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import { Label } from '@/shared/components/ui/label';
import { Combobox } from '@/shared/components/ui/combobox';
import {
  Mail,
  Lock,
  Loader2,
  AlertCircle,
  ChevronRight,
  ChevronLeft,
  CheckCircle2,
  Calendar,
  Phone,
  User,
  UserPlus,
} from 'lucide-react';

interface RegisterFormStepsProps {
  onSubmit: (data: RegisterDto) => Promise<void>;
  serverError: string | null;
  isSubmitting: boolean;
}

export const RegisterFormSteps: React.FC<RegisterFormStepsProps> = ({
  onSubmit,
  serverError,
  isSubmitting,
}) => {
  const [step, setStep] = React.useState(1);
  const TOTAL_STEPS = 4;

  const {
    provinces,
    cantons,
    districts,
    loadCantons,
    loadDistricts,
    loadingProvinces,
    loadingCantons,
    loadingDistricts,
  } = useGeo();

    control,
  } = useForm<RegisterDto>({
    resolver: classValidatorResolver(RegisterDto),
  });

  const selectedProvince = useWatch({ control, name: 'province' });
  const selectedCanton = useWatch({ control, name: 'canton' });
  const districtWatch = useWatch({ control, name: 'district' });
  const fullNameWatch = useWatch({ control, name: 'fullName' });
  const cedulaWatch = useWatch({ control, name: 'cedula' });
  const emailWatch = useWatch({ control, name: 'email' });

  const nextStep = async () => {
    type FieldName = keyof RegisterDto;
    let fieldsToValidate: FieldName[] = [];
    if (step === 1) fieldsToValidate = ['cedula', 'fullName', 'birthDate'];
    if (step === 2) fieldsToValidate = ['email', 'phone'];
    if (step === 3) fieldsToValidate = ['province', 'canton', 'district', 'town', 'exactAddress'];

    const isValid = await trigger(fieldsToValidate);
    if (isValid) setStep((s) => s + 1);
  };

  const prevStep = () => setStep((s) => s - 1);

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="mt-4">
      <div className="mb-6">
        <div className="flex justify-between items-center mb-2">
          <p className="text-sm text-zinc-400">
            Paso {step} de {TOTAL_STEPS}
          </p>
          <span className="text-xs font-medium text-blue-400">
            {step === 1 && 'Información Personal'}
            {step === 2 && 'Contacto'}
            {step === 3 && 'Ubicación'}
            {step === 4 && 'Seguridad'}
          </span>
        </div>
        <div className="w-full bg-white/5 h-1 rounded-full overflow-hidden">
          <div
            className="bg-blue-600 h-full transition-all duration-300"
            style={{ width: `${(step / TOTAL_STEPS) * 100}%` }}
          />
        </div>
      </div>

      <div className="space-y-6 min-h-[280px]">
        {serverError && (
          <div className="p-3 rounded-lg bg-red-500/10 border border-red-500/20 flex items-start gap-3 text-sm text-red-400">
            <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
            <p>{serverError}</p>
          </div>
        )}

        {/* Paso 1: Personal */}
        {step === 1 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="cedula" className="text-zinc-300">Cédula</Label>
              <div className="relative">
                <User className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="cedula" placeholder="0-0000-0000" className="pl-10 bg-white/5 border-white/10 text-white" {...register('cedula')} />
              </div>
              {errors.cedula && <p className="text-xs text-red-400">{errors.cedula.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="fullName" className="text-zinc-300">Nombre Completo</Label>
              <Input id="fullName" placeholder="Juan Pérez" className="bg-white/5 border-white/10 text-white" {...register('fullName')} />
              {errors.fullName && <p className="text-xs text-red-400">{errors.fullName.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="birthDate" className="text-zinc-300">Fecha de Nacimiento</Label>
              <div className="relative">
                <Calendar className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="birthDate" type="date" className="pl-10 bg-white/5 border-white/10 text-white" {...register('birthDate')} />
              </div>
              {errors.birthDate && <p className="text-xs text-red-400">{errors.birthDate.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 2: Contacto */}
        {step === 2 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="email" className="text-zinc-300">Correo Electrónico</Label>
              <div className="relative">
                <Mail className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="email" type="email" placeholder="juan@ejemplo.com" className="pl-10 bg-white/5 border-white/10 text-white" {...register('email')} />
              </div>
              {errors.email && <p className="text-xs text-red-400">{errors.email.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="phone" className="text-zinc-300">Teléfono</Label>
              <div className="relative">
                <Phone className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="phone" placeholder="8888-8888" className="pl-10 bg-white/5 border-white/10 text-white" {...register('phone')} />
              </div>
              {errors.phone && <p className="text-xs text-red-400">{errors.phone.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 3: Ubicación */}
        {step === 3 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label className="text-zinc-300">Provincia</Label>
                <Combobox
                  options={provinces.map((p) => ({ label: p.name, value: p.id }))}
                  value={selectedProvince}
                  onChange={(val) => {
                    setValue('province', val);
                    loadCantons(val);
                  }}
                  disabled={loadingProvinces}
                  placeholder="Provincia"
                />
                {errors.province && <p className="text-xs text-red-400">{errors.province.message}</p>}
              </div>
              <div className="space-y-2">
                <Label className="text-zinc-300">Cantón</Label>
                <Combobox
                  options={cantons.map((c) => ({ label: c.name, value: c.id }))}
                  value={selectedCanton}
                  onChange={(val) => {
                    setValue('canton', val);
                    loadDistricts(selectedProvince, val);
                  }}
                  disabled={!selectedProvince || loadingCantons}
                  placeholder="Cantón"
                />
                {errors.canton && <p className="text-xs text-red-400">{errors.canton.message}</p>}
              </div>
            </div>
            <div className="space-y-2">
              <Label className="text-zinc-300">Distrito</Label>
              <Combobox
                options={districts.map((d) => ({ label: d.name, value: d.id }))}
                value={districtWatch}
                onChange={(val) => setValue('district', val)}
                disabled={!selectedCanton || loadingDistricts}
                placeholder="Distrito"
              />
              {errors.district && <p className="text-xs text-red-400">{errors.district.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="town" className="text-zinc-300">Localidad</Label>
              <Input id="town" placeholder="San José Centro" className="bg-white/5 border-white/10 text-white" {...register('town')} />
              {errors.town && <p className="text-xs text-red-400">{errors.town.message}</p>}
            </div>
            <div className="space-y-2">
              <Label htmlFor="exactAddress" className="text-zinc-300">Dirección Exacta</Label>
              <Input id="exactAddress" placeholder="Frente a la plaza..." className="bg-white/5 border-white/10 text-white" {...register('exactAddress')} />
              {errors.exactAddress && <p className="text-xs text-red-400">{errors.exactAddress.message}</p>}
            </div>
          </div>
        )}

        {/* Paso 4: Seguridad */}
        {step === 4 && (
          <div className="space-y-4 animate-in slide-in-from-right-4">
            <div className="space-y-2">
              <Label htmlFor="pass" className="text-zinc-300">Contraseña</Label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-4 w-4 text-zinc-500" />
                <Input id="pass" type="password" placeholder="••••••••" className="pl-10 bg-white/5 border-white/10 text-white" {...register('password')} />
              </div>
              {errors.password && <p className="text-xs text-red-400">{errors.password.message}</p>}
            </div>
            <div className="p-4 bg-blue-500/5 border border-blue-500/10 rounded-lg space-y-2">
              <h4 className="text-sm font-medium text-blue-400 flex items-center gap-2">
                <CheckCircle2 className="w-4 h-4" /> Resumen de Cuenta
              </h4>
              <div className="text-xs text-zinc-400 space-y-1">
                <p>Nombre: {fullNameWatch}</p>
                <p>Cédula: {cedulaWatch}</p>
                <p>Correo: {emailWatch}</p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Navegación */}
      <div className="flex justify-between gap-4 mt-8 pt-6 border-t border-white/6">
        {step > 1 ? (
          <Button type="button" variant="outline" onClick={prevStep} className="border-white/10 text-white hover:bg-white/5">
            <ChevronLeft className="w-4 h-4 mr-2" /> Atrás
          </Button>
        ) : (
          <div />
        )}

        {step < TOTAL_STEPS ? (
          <Button type="button" onClick={nextStep} className="bg-blue-600 hover:bg-blue-500">
            Siguiente <ChevronRight className="w-4 h-4 ml-2" />
          </Button>
        ) : (
          <Button type="submit" disabled={isSubmitting} className="bg-blue-600 hover:bg-blue-500 min-w-[140px]">
            {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <UserPlus className="w-4 h-4 mr-2" />}
            {isSubmitting ? 'Registrando...' : 'Crear Cuenta'}
          </Button>
        )}
      </div>
    </form>
  );
};

'use client';

import React, { 
  createContext, 
  useContext, 
  useEffect, 
  useState, 
  useCallback,
  useMemo
} from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { AuthUser, LoginPayload, RegisterPayload } from '@/shared/api/api-types';
import { AuthService } from '../services/auth.service';
import { setupInterceptors } from '@/shared/api/interceptors';
import { apiClient } from '@/shared/api/api-client';
import { useQuery, useQueryClient } from '@tanstack/react-query';

export type AuthStatus = 'idle' | 'checking' | 'authenticated' | 'guest';

interface AuthContextType {
  user: AuthUser | null;
  status: AuthStatus;
  isAuthenticated: boolean;
  isAdmin: boolean;
  isCustomer: boolean;
  login: (payload: LoginPayload) => Promise<void>;
  register: (payload: RegisterPayload) => Promise<void>;
  logout: (options?: { localOnly?: boolean }) => Promise<void>;
  refreshUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

const AUTH_CHANNEL_NAME = 'astroassist_auth_channel';
const PROTECTED_ROUTES = ['/dashboard', '/profile', '/settings', '/checkout', '/admin'];

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const router = useRouter();
  const pathname = usePathname();
  const queryClient = useQueryClient();

  // ── Sincronización Cross-Tab ──────────────────────────────────────────
  const authChannel = useMemo(() => {
    if (typeof window === 'undefined') return null;
    return new BroadcastChannel(AUTH_CHANNEL_NAME);
  }, []);

  // ── Sesión con TanStack Query ─────────────────────────────────────────
  const { 
    data: sessionResponse, 
    status: queryStatus,
    fetchStatus,
    refetch 
  } = useQuery({
    queryKey: ['auth', 'session'],
    queryFn: () => AuthService.getMe(),
    retry: false,
    staleTime: 1000 * 60 * 5, // 5 minutos de validez
  });

  const user = sessionResponse?.data || null;

  // Derivación de estado para compatibilidad
  const status = useMemo((): AuthStatus => {
    if (queryStatus === 'pending' && fetchStatus === 'fetching') return 'checking';
    if (user) return 'authenticated';
    return 'guest';
  }, [queryStatus, fetchStatus, user]);

  const logout = useCallback(async (options?: { localOnly?: boolean }) => {
    try {
      if (!options?.localOnly) {
        await AuthService.logout();
        authChannel?.postMessage({ type: 'LOGOUT' });
      }
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      queryClient.setQueryData(['auth', 'session'], null);

      const isProtected = PROTECTED_ROUTES.some(route => pathname.includes(route));
      if (isProtected) {
        router.push('/');
      }
    }
  }, [authChannel, pathname, router, queryClient]);

  const login = useCallback(async (payload: LoginPayload) => {
    const response = await AuthService.login(payload);
    queryClient.setQueryData(['auth', 'session'], response);
    authChannel?.postMessage({ type: 'LOGIN' });
    router.push('/');
  }, [queryClient, authChannel, router]);

  const register = useCallback(async (payload: RegisterPayload) => {
    const response = await AuthService.register(payload);
    queryClient.setQueryData(['auth', 'session'], response);
    authChannel?.postMessage({ type: 'LOGIN' });
    router.push('/');
  }, [queryClient, authChannel, router]);

  const refreshUser = useCallback(async () => {
    await refetch();
  }, [refetch]);

  // ── SSE: Eventos de Seguridad ─────────────────────────────────────────
  useEffect(() => {
    if (status !== 'authenticated' || !user) return;

    const streamUrl = `${apiClient.defaults.baseURL}/sessions/stream`;
    const eventSource = new EventSource(streamUrl, { withCredentials: true });

    eventSource.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.type === 'FORCE_LOGOUT' || data.type === 'SESSION_REVOKED') {
          console.warn(`⚠️ [Auth] Sesión invalidada por el servidor: ${data.type}`);
          logout({ localOnly: true });
        }
      } catch (err) {
        console.error('Error parsing SSE message:', err);
      }
    };

    eventSource.onerror = (err) => {
      console.error('SSE Error:', err);
      eventSource.close();
    };

    return () => {
      eventSource.close();
    };
  }, [status, user, logout]);

  // ── Inicialización ──────────────────────────────────────────────────
  useEffect(() => {
    setupInterceptors(apiClient, logout);

    if (authChannel) {
      authChannel.onmessage = (event) => {
        if (event.data.type === 'LOGOUT') {
          logout({ localOnly: true });
        } else if (event.data.type === 'LOGIN') {
          refetch();
        }
      };
    }

    return () => {
      authChannel?.close();
    };
  }, [logout, refetch, authChannel]);

  const value = useMemo(() => ({
    user,
    status,
    isAuthenticated: status === 'authenticated',
    isAdmin: user?.role === 'ADMIN',
    isCustomer: user?.role === 'CUSTOMER',
    login,
    register,
    logout,
    refreshUser,
  }), [user, status, login, register, logout, refreshUser]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

"use client";

import { motion } from "framer-motion";
import { ShoppingCart, Plus, Check } from "lucide-react";
import { useState } from "react";
import { Product } from "@/features/catalog/types";
import { useCart } from "@/features/cart/hooks/useCart";
import { Button } from "@/shared/components/ui/button";
import { cn } from "@/shared/utils/cn";

interface BuySetupButtonProps {
  products: Product[];
  locale: "en" | "es";
  className?: string;
  variant?: "primary" | "secondary" | "outline";
}

export function BuySetupButton({ 
  products, 
  locale, 
  className,
  variant = "primary" 
}: BuySetupButtonProps) {
  const { addBundle } = useCart();
  const [isAdded, setIsAdded] = useState(false);

  if (!products || products.length === 0) return null;

  const totalPrice = products.reduce((sum, p) => {
    // Parse price string like "$1,299.00" or similar
    const num = parseFloat(p.price.replace(/[$,]/g, ""));
    return sum + (isNaN(num) ? 0 : num);
  }, 0);

  const formattedPrice = new Intl.NumberFormat(locale === "en" ? "en-US" : "es-ES", {
    style: "currency",
    currency: "USD",
  }).format(totalPrice);

  const handleAdd = () => {
    addBundle(products);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  const label = locale === "en" ? "Buy Full Setup" : "Comprar Setup Completo";
  const addedLabel = locale === "en" ? "Added to Cart!" : "¡Añadido al Carrito!";
  const itemsLabel = locale === "en" ? "items" : "productos";

  return (
    <Button
      onClick={handleAdd}
      className={cn(
        "group relative overflow-hidden rounded-full h-14 px-8 transition-all duration-500",
        variant === "primary" ? "bg-primary text-on-primary hover:bg-primary-hover shadow-xl shadow-primary/20" : "",
        variant === "secondary" ? "bg-surface-container-highest text-text-main hover:bg-surface-bright" : "",
        className
      )}
      disabled={isAdded}
    >
      <motion.div
        animate={{ y: isAdded ? -40 : 0 }}
        className="flex items-center gap-3"
      >
        <div className="flex flex-col items-start leading-tight">
          <span className="text-label-md font-bold tracking-tight">{label}</span>
          <span className="text-[10px] opacity-70 uppercase tracking-widest font-medium">
            {products.length} {itemsLabel} • {formattedPrice}
          </span>
        </div>
        <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center group-hover:scale-110 transition-transform">
          <ShoppingCart className="w-4 h-4" />
        </div>
