"use client";

import React, { createContext, useContext, useReducer, useEffect, useState, useMemo, useCallback } from "react";
import { CartItem, CartState, CartAction, CartSummary } from "../types";
import { calculateCartSummary, validateQuantity } from "../utils/cart-logic";
import { mapProductToCartItem } from "../utils/cartMapper";
import { Product } from "@/features/catalog/types";

import productsData from "@/features/catalog/data/products.json";

const CART_STORAGE_KEY = "astroassist-cart";

const initialState: CartState = {
  items: [],
  isOpen: false,
};

function cartReducer(state: CartState, action: CartAction): CartState {
  switch (action.type) {
    case "ADD_ITEM": {
      const { product, quantity } = action.payload;
      const validatedQty = validateQuantity(quantity);
      const existingItemIndex = state.items.findIndex((item) => item.productId === product.id);

      if (existingItemIndex > -1) {
        const newItems = [...state.items];
        newItems[existingItemIndex].quantity = validateQuantity(newItems[existingItemIndex].quantity + validatedQty);
        return { ...state, items: newItems, isOpen: true };
      }

      const newItem = mapProductToCartItem(product, validatedQty);

      return { ...state, items: [...state.items, newItem], isOpen: true };
    }

    case "REMOVE_ITEM":
      return {
        ...state,
        items: state.items.filter((item) => item.productId !== action.payload.productId),
      };

    case "UPDATE_QUANTITY": {
      const { productId, quantity } = action.payload;
      return {
        ...state,
        items: state.items.map((item) =>
          item.productId === productId ? { ...item, quantity: validateQuantity(quantity) } : item
        ),
      };
    }

    case "INCREMENT_QUANTITY":
      return {
        ...state,
        items: state.items.map((item) =>
          item.productId === action.payload.productId ? { ...item, quantity: validateQuantity(item.quantity + 1) } : item
        ),
      };

    case "DECREMENT_QUANTITY":
      return {
        ...state,
        items: state.items.map((item) =>
          item.productId === action.payload.productId
            ? { ...item, quantity: validateQuantity(item.quantity - 1) }
            : item
        ),
      };

    case "CLEAR_CART":
      return { ...state, items: [] };

    case "ADD_BUNDLE": {
      const { products } = action.payload;
      const newItems = [...state.items];

      products.forEach((product) => {
        const existingItemIndex = newItems.findIndex((item) => item.productId === product.id);
        if (existingItemIndex > -1) {
          newItems[existingItemIndex].quantity = validateQuantity(newItems[existingItemIndex].quantity + 1);
        } else {
          newItems.push(mapProductToCartItem(product, 1));
        }
      });

      return { ...state, items: newItems, isOpen: true }; // Open cart when bundle added
    }

    case "SET_CART":
      return { ...state, items: action.payload };

    case "TOGGLE_CART":
      return { ...state, isOpen: !state.isOpen };

    case "SET_OPEN":
      return { ...state, isOpen: action.payload };

    default:
      return state;
  }
}

interface CartContextType extends CartState {
  summary: CartSummary;
  addItem: (product: Product, quantity?: number) => void;
  addBundle: (products: Product[]) => void;
  removeItem: (productId: string) => void;
  updateQuantity: (productId: string, quantity: number) => void;
  incrementQuantity: (productId: string) => void;
  decrementQuantity: (productId: string) => void;
  clearCart: () => void;
  toggleCart: () => void;
  setOpen: (isOpen: boolean) => void;
  isInCart: (productId: string) => boolean;
  getItemQuantity: (productId: string) => number;
  isHydrated: boolean;
}

const CartContext = createContext<CartContextType | null>(null);

export function CartProvider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = useReducer(cartReducer, initialState);
  const [isHydrated, setIsHydrated] = useState(false);

  // Persistence: Load from localStorage & Cleanup stale items
  useEffect(() => {
    const savedCart = localStorage.getItem(CART_STORAGE_KEY);
    if (savedCart) {
      try {
        const items: CartItem[] = JSON.parse(savedCart);

        // Filter out items that are no longer in the catalog
        const validItems = items.filter(item => 
          productsData.some(p => p.id === item.productId)
        );

        // Re-validate all quantities just in case
        const sanitizedItems = validItems.map(item => ({
          ...item,
          quantity: validateQuantity(item.quantity)
        }));

        dispatch({ type: "SET_CART", payload: sanitizedItems });
      } catch (error) {
        console.error("Failed to parse cart from localStorage", error);
      }
    }
    setIsHydrated(true);
  }, []);

  // Persistence: Save to localStorage
  useEffect(() => {
    if (isHydrated) {
      localStorage.setItem(CART_STORAGE_KEY, JSON.stringify(state.items));
    }
  }, [state.items, isHydrated]);

  const summary = useMemo(() => calculateCartSummary(state.items), [state.items]);

  const addItem = useCallback((product: Product, quantity = 1) => 
    dispatch({ type: "ADD_ITEM", payload: { product, quantity } }), []);

  const addBundle = useCallback((products: Product[]) => 
    dispatch({ type: "ADD_BUNDLE", payload: { products } }), []);

  const removeItem = useCallback((productId: string) => 
    dispatch({ type: "REMOVE_ITEM", payload: { productId } }), []);

  const updateQuantity = useCallback((productId: string, quantity: number) =>
    dispatch({ type: "UPDATE_QUANTITY", payload: { productId, quantity } }), []);

  const incrementQuantity = useCallback((productId: string) => 
    dispatch({ type: "INCREMENT_QUANTITY", payload: { productId } }), []);

  const decrementQuantity = useCallback((productId: string) => 
    dispatch({ type: "DECREMENT_QUANTITY", payload: { productId } }), []);

  const clearCart = useCallback(() => dispatch({ type: "CLEAR_CART" }), []);
  const toggleCart = useCallback(() => dispatch({ type: "TOGGLE_CART" }), []);
  const setOpen = useCallback((isOpen: boolean) => 
    dispatch({ type: "SET_OPEN", payload: isOpen }), []);

  const isInCart = useCallback((productId: string) => 
    state.items.some((item) => item.productId === productId), [state.items]);

  const getItemQuantity = useCallback((productId: string) => 
    state.items.find((item) => item.productId === productId)?.quantity || 0, [state.items]);

  const contextValue = useMemo(() => ({
    ...state,
    summary,
    addItem,
    addBundle,
    removeItem,
    updateQuantity,
    incrementQuantity,
    decrementQuantity,
    clearCart,
    toggleCart,
    setOpen,
    isInCart,
    getItemQuantity,
    isHydrated,
  }), [
    state,
    summary,
    addItem,
    addBundle,
    removeItem,
    updateQuantity,
    incrementQuantity,
    decrementQuantity,
    clearCart,
    toggleCart,
    setOpen,
    isInCart,
    getItemQuantity,
    isHydrated,
  ]);

  return (
    <CartContext.Provider value={contextValue}>
      {children}
    </CartContext.Provider>
  );
}

export function useCartContext() {
  const context = useContext(CartContext);
  if (!context) {
    throw new Error("useCartContext must be used within a CartProvider");
  }
  return context;
}

"use client";

import { motion, useMotionTemplate, useMotionValue, useSpring, useTransform } from "framer-motion";
import Image from "next/image";
import { ShoppingCart, ArrowRight, Zap } from "lucide-react";
import { Badge } from "@/shared/components/ui/badge";
import { Button } from "@/shared/components/ui/button";
import { useCart } from "@/features/cart";
import Link from "next/link";
import type { Product, RecommendedLevel, ObservationType, SkyCondition } from "@/features/catalog";

// ─────────────────────────────────────────────────────────────────────────────
// Badge color maps
// ─────────────────────────────────────────────────────────────────────────────

const levelColors: Record<RecommendedLevel, string> = {
  beginner: "bg-success-container/30 text-on-success-container border-success-container/40",
  intermediate: "bg-warning-container/30 text-on-warning-container border-warning-container/40",
  advanced: "bg-error-container/30 text-on-error-container border-error-container/40",
};

const goalLabels: Record<ObservationType, Record<"en" | "es", string>> = {
  planetary: { en: "Planets", es: "Planetas" },
  deep_sky: { en: "Deep Sky", es: "Cielo Profundo" },
  astrophotography: { en: "Astrophotography", es: "Astrofotografía" },
  general: { en: "General", es: "General" },
};

const skyHints: Record<SkyCondition, Record<"en" | "es", string>> = {
  city: { en: "Great for city skies", es: "Ideal para cielos urbanos" },
  suburban: { en: "Works in suburban skies", es: "Funciona en suburbios" },
  dark_sky: { en: "Best at dark sites", es: "Mejor en cielo oscuro" },
};

const levelLabels: Record<RecommendedLevel, Record<"en" | "es", string>> = {
  beginner: { en: "Beginner", es: "Principiante" },
  intermediate: { en: "Intermediate", es: "Intermedio" },
  advanced: { en: "Advanced", es: "Avanzado" },
};

// ─────────────────────────────────────────────────────────────────────────────
// ProductCard
// ─────────────────────────────────────────────────────────────────────────────

interface CatalogProductCardProps {
  product: Product;
  index: number;
  locale: "en" | "es";
  isHighlighted?: boolean;
}

export function CatalogProductCard({
  product,
  index,
  locale,
  isHighlighted = false,
}: CatalogProductCardProps) {
  const name = locale === "en" ? product.nameEn : product.nameEs;
  const description = locale === "en" ? product.descriptionEn : product.descriptionEs;

  const { addItem, setOpen } = useCart();

  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const mouseX = useSpring(x, { stiffness: 300, damping: 30 });
  const mouseY = useSpring(y, { stiffness: 300, damping: 30 });

  function onMouseMove({ currentTarget, clientX, clientY }: React.MouseEvent) {
    const { left, top, width, height } = currentTarget.getBoundingClientRect();
    x.set(clientX - left - width / 2);
    y.set(clientY - top - height / 2);
  }
  function onMouseLeave() {
    x.set(0);
    y.set(0);
  }

  const rotateX = useTransform(mouseY, [-200, 200], [8, -8]);
  const rotateY = useTransform(mouseX, [-200, 200], [-8, 8]);
  const glare = useMotionTemplate`radial-gradient(300px circle at ${mouseX}px ${mouseY}px, rgba(98,87,244,0.12), transparent 80%)`;

  const compatibleCount = product.compatibility.length;

  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-80px" }}
      transition={{ duration: 0.6, delay: index * 0.1, ease: [0.22, 1, 0.36, 1] }}
      style={{ perspective: 1000 }}
      className="h-full"
    >
      <motion.div
        onMouseMove={onMouseMove}
        onMouseLeave={onMouseLeave}
        style={{ rotateX, rotateY, transformStyle: "preserve-3d" }}
        className={`relative flex flex-col h-full rounded-xl border bg-surface-container-low overflow-hidden group transition-all duration-500 will-change-transform ${
          isHighlighted
            ? "border-primary/40 shadow-[0_0_30px_rgba(98,87,244,0.15)]"
            : "border-white/5 hover:border-white/10 hover:shadow-2xl hover:shadow-primary/10"
        }`}
      >
        <Link href={`/${locale}/catalogo/${product.id}`} className="absolute inset-0 z-40" aria-label={`View ${name}`} />
        {/* Glare */}
        <motion.div
          className="pointer-events-none absolute -inset-px z-30 opacity-0 group-hover:opacity-100 transition-opacity duration-300 mix-blend-screen rounded-xl overflow-hidden"
          style={{ background: glare }}
        />

        {/* Image */}
        <div
          className="relative w-full h-[220px] overflow-hidden bg-surface-container-lowest"
          style={{ transform: "translateZ(20px)" }}
        >
          <div className="absolute inset-0 bg-linear-to-b from-transparent via-transparent to-surface-container-low z-10" />
          <Image
            src={product.images.primary}
            alt={name}
            fill
            sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
            className="object-cover opacity-60 group-hover:opacity-100 group-hover:scale-105 transition-all duration-700 ease-out"
          />

          {/* Level badge — top left */}
          <div className="absolute top-4 left-4 z-20">
            <span
              className={`inline-flex items-center px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border ${levelColors[product.recommendedLevel]}`}
            >
              {levelLabels[product.recommendedLevel][locale]}
            </span>
          </div>

          {/* Best for — top right */}
          <div className="absolute top-4 right-4 z-20">
            <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider bg-surface-container-high/80 border border-white/10 text-text-muted backdrop-blur-md">
              {goalLabels[product.observationType][locale]}
            </span>
          </div>
        </div>

        {/* Content */}
        <div
          className="flex flex-col flex-1 px-6 pb-6 pt-4 relative z-20"
          style={{ transform: "translateZ(30px)" }}
        >
          {/* Sky hint */}
          <p className="text-label-sm text-primary font-bold mb-3 flex items-center gap-1.5 uppercase">
            <Zap className="w-3.5 h-3.5" />
            {skyHints[product.skyCondition][locale]}
          </p>

          <h3 className="text-title-lg font-semibold tracking-tight text-text-main mb-2 group-hover:text-primary transition-all duration-300">
            {name}
          </h3>

          <p className="text-body-sm text-text-soft leading-relaxed font-light line-clamp-2 mb-6">
            {description}
          </p>

          {/* Tags */}
          <div className="flex flex-wrap gap-1.5 mb-6">
            {product.tags.slice(0, 3).map((tag) => (
              <span
                key={tag}
                className="px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider bg-white/5 border border-white/10 text-text-faint"
              >
                {tag}
              </span>
            ))}
          </div>

          <div className="mt-auto flex items-end justify-between gap-3">
            <div>
              <span className="text-headline-md font-bold text-text-main font-mono tracking-tight">
                {product.price}
              </span>
              {compatibleCount > 0 && (
                <p className="text-label-sm text-text-faint mt-1 flex items-center gap-1 font-medium">
                  <ArrowRight className="w-3.5 h-3.5" />
                  {locale === "en"
                    ? `${compatibleCount} compatible items`
                    : `${compatibleCount} accesorios compatibles`}
                </p>
              )}
            </div>

            <Button
              size="icon"
              variant="primary"
              className="h-12 w-12 rounded-xl shrink-0 shadow-lg shadow-primary/20 relative z-50"
              onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                addItem(product, 1);
                setOpen(true);
              }}
            >
              <ShoppingCart className="w-5 h-5" />
            </Button>
          </div>
        </div>

        {/* Bottom glow sweep */}
        <div className="absolute bottom-0 left-0 w-full h-[2px] bg-linear-to-r from-transparent via-primary to-transparent scale-x-0 group-hover:scale-x-100 transition-transform duration-700 origin-center" />
      </motion.div>
    </motion.div>
  );
}

"use client";

import { AnimatePresence, motion } from "framer-motion";
import { Search } from "lucide-react";
import { CatalogProductCard } from "./ProductCard";
import type { ScoredProduct } from "@/features/catalog";

interface ProductGridProps {
  products: ScoredProduct[];
  locale: "en" | "es";
  isFiltered: boolean;
}

export function ProductGrid({ products, locale, isFiltered }: ProductGridProps) {
  const emptyTitle = locale === "en" ? "No matching equipment found" : "No se encontró equipo compatible";
  const emptyDesc = locale === "en"
    ? "Try adjusting your filters or clearing some selections to see more options."
    : "Intenta ajustar tus filtros o limpiar algunas selecciones para ver más opciones.";

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8 min-h-[40vh]">
      <AnimatePresence mode="popLayout">
        {products.map(({ product, score, matchReasons }, index) => (
          <motion.div
            key={product.id}
            layout
            initial={{ opacity: 0, scale: 0.85, filter: "blur(8px)" }}
            animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
