"use client";

import { cn } from "@/shared/utils/cn";
import { Avatar, AvatarFallback } from "@/shared/components/ui/avatar";
import Image from "next/image";
import { Bot, User, Sparkles, AlertCircle, Info, ArrowRight } from "lucide-react";
import { Message } from "@/features/chat";
import { useRouter, useParams } from "next/navigation";
import ReactMarkdown from "react-markdown";
import React, { isValidElement } from "react";
import remarkGfm from "remark-gfm";
import productsData from "@/features/catalog/data/products.json";
import type { Product } from "@/features/catalog";

const products = productsData as Product[];

export function ChatMessage({ message }: { message: Message }) {
  const isBot = message.role === "assistant";
  const router = useRouter();
  const params = useParams();
  const locale = (params.locale as string) || "es";

  const dateObj = message.createdAt instanceof Date 
    ? message.createdAt 
    : new Date(message.createdAt || Date.now());

  // Helper to render text with nested product cards
  const renderTextWithProducts = (text: string) => {
    if (!text.includes("[[PRODUCT:") || !text.includes("]]")) {
      return text;
    }

    const parts = text.split(/(\[\[PRODUCT:.*?\]\])/g);
    return (
      <div className="space-y-4 my-2">
        {parts.map((part, i) => {
          if (part.startsWith("[[PRODUCT:") && part.endsWith("]]")) {
            const productId = part.replace("[[PRODUCT:", "").replace("]]", "").trim();
            const product = products.find(p => p.id === productId);
            if (!product) return null;
            
            return (
              <div key={i} className="bg-surface-container border border-white/5 rounded-xl overflow-hidden flex items-center gap-4 p-4 group hover:bg-surface-bright transition-all duration-300 shadow-xl animate-in fade-in slide-in-from-bottom-2">
                <div className="w-16 h-16 rounded-lg overflow-hidden bg-background shrink-0 relative border border-white/5">
                  <Image 
                    src={product.images.primary} 
                    alt={product.nameEn} 
                    fill
                    sizes="64px"
                    className="object-cover opacity-90 group-hover:opacity-100 group-hover:scale-105 transition-all duration-700" 
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <h4 className="text-body-sm font-bold text-text-main group-hover:text-primary transition-colors leading-tight mb-0.5">{product.nameEs}</h4>
                      <p className="text-[10px] text-primary font-bold tracking-widest uppercase">{product.category}</p>
                    </div>
                    <span className="text-xs font-mono font-bold text-text-muted">{product.price}</span>
                  </div>
                  <div className="flex items-center justify-between mt-2 pt-2 border-t border-white/5">
                    <span className="text-[10px] text-text-faint uppercase tracking-tighter">{product.recommendedLevel}</span>
                    <button 
                      onClick={() => router.push(`/${locale}/catalogo?search=${product.id}`)}
                      className="text-[10px] text-primary hover:text-primary-hover transition-colors flex items-center gap-1 font-bold cursor-pointer bg-transparent border-none p-0"
                    >
                      {locale === 'en' ? 'Details' : 'Detalles'} <ArrowRight className="w-2.5 h-2.5" />
                    </button>
                  </div>
                </div>
              </div>
            );
          }
          return part ? <span key={i}>{part}</span> : null;
        })}
      </div>
    );
  };

  const renderContent = (content: string) => {
    return (
      <ReactMarkdown 
        remarkPlugins={[remarkGfm]}
        components={{
          h1: ({ children }) => <h1 className="text-title-md font-bold mt-4 mb-2 text-text-main">{children}</h1>,
          h2: ({ children }) => <h2 className="text-body-md font-bold mt-3 mb-1 text-primary">{children}</h2>,
          p: ({ children }) => {
            const text = isValidElement(children) 
              ? "" 
              : Array.isArray(children) 
                ? children.map(c => (typeof c === 'string' ? c : '')).join("")
                : String(children || "");

            const ALLOWED_HEADERS = ["ENTENDIMIENTO", "RECOMENDACIÓN", "POR QUÉ", "PRÓXIMO PASO", "CONSEJO", "TÉCNICA", "CONFIGURACIÓN"];
            
            // Si el texto contiene patrones tipo [HEADER], lo dividimos para procesar cada badge
            const headerRegex = new RegExp(`\\[(${ALLOWED_HEADERS.join("|")})\\]`, "gi");
            
            if (headerRegex.test(text)) {
              // Dividimos el texto manteniendo los delimitadores
              const parts = text.split(/(\[(?:ENTENDIMIENTO|RECOMENDACIÓN|POR QUÉ|PRÓXIMO PASO|CONSEJO|TÉCNICA|CONFIGURACIÓN)\])/gi);
              
              return (
                <div className="flex flex-col gap-1">
                  {parts.map((part, i) => {
                    const cleanPart = part.trim();
                    if (!cleanPart) return null;
                    
                    const headerMatch = cleanPart.match(/^\[(.*)\]$/);
                    const headerKey = headerMatch ? headerMatch[1].toUpperCase() : null;
                    
                    if (headerKey && ALLOWED_HEADERS.includes(headerKey)) {
                      return (
                        <div key={i} className="mt-6 mb-2 first:mt-2 animate-in fade-in slide-in-from-left-2 duration-500">
                          <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-primary-container text-[10px] uppercase font-black tracking-widest text-on-primary-container mb-2.5 shadow-sm shadow-primary/10">
                            <Sparkles className="w-2.5 h-2.5" /> {headerKey}
                          </span>
                        </div>
                      );
                    }
                    
                    return (
                      <p key={i} className="mb-4 last:mb-0 text-body-sm leading-relaxed text-text-soft/90 tracking-tight pl-3 border-l-2 border-primary/20 ml-1">
                        {renderTextWithProducts(cleanPart)}
                      </p>
                    );
                  })}
                </div>
              );
            }
            
            return (
              <p className="mb-4 last:mb-0 text-body-sm leading-relaxed text-text-soft/90 tracking-tight">
                {renderTextWithProducts(text)}
              </p>
            );
          },
          ul: ({ children }) => <ul className="space-y-2 mb-4 list-none">{children}</ul>,
          li: ({ children }) => (
            <li className="flex gap-2 text-body-sm text-text-muted">
              <span className="text-primary mt-1.5">•</span>
              <span>{children}</span>
            </li>
          ),
          strong: ({ children }) => <strong className="font-bold text-text-main tracking-tight">{children}</strong>,
          code: ({ children }) => <code className="bg-surface-bright px-1.5 py-0.5 rounded text-[11px] font-mono text-primary-hover">{children}</code>,
        }}
      >
        {content}
      </ReactMarkdown>
    );
  };

  return (
    <div className={cn("flex w-full gap-3", isBot ? "justify-start" : "justify-end")}>
      {isBot && (
        <Avatar className="w-10 h-10 border border-primary/20 bg-primary-container mt-1 flex items-center justify-center shrink-0">
          <AvatarFallback className="bg-transparent">
            <Bot className="w-5 h-5 text-primary" />
          </AvatarFallback>
        </Avatar>
      )}
      
      <div 
        className={cn(
          "max-w-[88%] px-5 py-4 rounded-2xl",
          isBot 
            ? "bg-surface-container-high text-text-soft rounded-tl-sm border border-white/5 shadow-xl" 
            : "bg-primary text-on-primary rounded-tr-sm shadow-lg shadow-primary/20"
        )}
      >
        <div className="prose prose-invert prose-sm max-w-none">
          {renderContent(message.content)}
        </div>
        
        <div className={cn(
          "flex items-center gap-2 mt-3 pt-3 border-t border-white/5",
          !isBot && "justify-end border-white/10"
        )}>
          {isBot && <Sparkles className="w-3 h-3 text-primary opacity-50" />}
          <span className={cn(
            "text-[10px] opacity-40 font-bold tracking-widest uppercase",
            !isBot && "text-right"
          )}>
            {dateObj.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
            {isBot && " • AstroAssist Expert"}
          </span>
        </div>
      </div>

      {!isBot && (
        <Avatar className="w-10 h-10 border border-primary/20 bg-primary mt-1 flex items-center justify-center shrink-0">
          <AvatarFallback className="bg-transparent">
            <User className="w-5 h-5 text-on-primary" />
          </AvatarFallback>
        </Avatar>
      )}
    </div>

  );
}

"use client";

import { useRef, useEffect } from "react";
import { Bot, Trash2 } from "lucide-react";
import { cn } from "@/shared/utils/cn";
import { Button } from "@/shared/components/ui/button";
import { ChatMessage } from "./ChatMessage";
import { MessageInput } from "./MessageInput";
import { useChat } from "@/features/chat";

export function ChatWindow() {
  const { messages, input, setInput, sendMessage, isLoading, error, status, clearHistory } = useChat();
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll logic
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const getStatusConfig = () => {
    if (isLoading) return { color: "bg-warning", label: "Procesando...", pulse: true };
    
    switch (status) {
      case 'error_auth': return { color: "bg-error", label: "Error de Configuración", pulse: false };
      case 'error_quota': return { color: "bg-warning", label: "Límite de Cuota (Free)", pulse: false };
      case 'error_model': return { color: "bg-error", label: "Modelo no Disponible", pulse: false };
      case 'offline': return { color: "bg-text-muted", label: "Servidor Desconectado", pulse: false };
      default: return { color: "bg-success", label: "Sistemas Online", pulse: false };
    }
  };

  const statusConfig = getStatusConfig();

  return (
    <div className="flex flex-col h-full w-full bg-surface-container-low/95 backdrop-blur-3xl">
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-5 border-b border-white/5 bg-surface-container/50 backdrop-blur-md shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center border border-primary/20 relative shadow-inner">
            <Bot className={cn("w-6 h-6 text-primary transition-all duration-500", isLoading && "animate-pulse scale-110 text-primary-hover")} />
            <span className={cn(
              "absolute bottom-0.5 right-0.5 w-3 h-3 rounded-full border-2 border-background transition-all duration-500 shadow-lg",
              statusConfig.color,
              statusConfig.pulse && "animate-pulse shadow-sm shadow-current"
            )} />
          </div>
          <div>
            <h3 className="font-bold text-text-main tracking-tight text-sm">AstroAssist AI</h3>
            <p className={cn(
              "text-[10px] font-black uppercase tracking-widest transition-colors duration-500",
              statusConfig.color.replace('bg-', 'text-')
            )}>
              {statusConfig.label}
            </p>
          </div>
        </div>
        
        <Button 
          variant="ghost" 
          size="icon" 
          onClick={clearHistory}
          title="Borrar historial"
          className="text-text-muted hover:text-error hover:bg-error/10 transition-colors h-10 w-10"
        >
          <Trash2 className="w-4 h-4" />
        </Button>
      </div>

      {/* Messages Area - Native overflow scroll for reliable scrollTop manipulation */}
      <div className="flex-1 p-6 overflow-y-auto" ref={scrollRef}>
        <div className="flex flex-col gap-6 pb-4 min-h-full justify-end">
          {messages.map((message) => (
            <ChatMessage key={message.id} message={message} />
          ))}
          
          {isLoading && (
            <div className="flex w-full justify-start gap-3 animate-in fade-in duration-300">
              <div className="w-10 h-10 rounded-full border border-primary/20 bg-primary-container mt-1 flex items-center justify-center shrink-0">
                <Bot className="w-5 h-5 text-primary" />
              </div>
              <div className="bg-surface-container-high px-5 py-4 rounded-xl rounded-tl-sm border border-white/5 flex items-center gap-1.5 shadow-xl">
                <span className="w-2 h-2 rounded-full bg-primary/60 animate-bounce" style={{ animationDelay: "0ms" }} />
                <span className="w-2 h-2 rounded-full bg-primary/60 animate-bounce" style={{ animationDelay: "150ms" }} />
                <span className="w-2 h-2 rounded-full bg-primary/60 animate-bounce" style={{ animationDelay: "300ms" }} />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Input Area */}
      <div className="p-5 bg-surface-container/50 border-t border-white/5 backdrop-blur-md shrink-0">
        <MessageInput 
          input={input}
          setInput={setInput}
          onSubmit={sendMessage}
          isLoading={isLoading}
        />
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "@/shared/components/ui/button";
import { Card } from "@/shared/components/ui/card";
import { Input } from "@/shared/components/ui/input";
import { useTranslations } from "@/shared/providers/i18n-provider";
import { CheckoutStep, PaymentMethod, ShippingMethod } from "../types";
import { 
  ArrowRight, 
  ArrowLeft, 
  CreditCard, 
  Wallet, 
  Truck, 
  Landmark, 
  Phone, 
  Globe, 
  FileText,
  Check,
  Loader2
} from "lucide-react";
import { cn } from "@/shared/utils/cn";

/**
 * Props for the CheckoutForm component
 */
interface CheckoutFormProps {
  step: CheckoutStep;
  onNext: (data: any) => void;
  onPrev: () => void;
  shippingMethod: ShippingMethod;
  setShippingMethod: (method: ShippingMethod) => void;
}

export function CheckoutForm({ step, onNext, onPrev, shippingMethod, setShippingMethod }: CheckoutFormProps) {
  const t = useTranslations();
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Local state for form data management
  const [formData, setFormData] = useState({
    email: "",
    fullName: "",
    phone: "",
    address: "",
    city: "",
    country: "",
    zipCode: "",
    notes: "",
    cardNumber: "",
    expiry: "",
    cvc: ""
  });

  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>("credit_card");
  const [errors, setErrors] = useState<Record<string, boolean>>({});

  /**
   * Validate current step fields
   */
  const validate = () => {
    const newErrors: Record<string, boolean> = {};

    if (step === "shipping") {
      if (!formData.fullName.trim()) newErrors.fullName = true;
      if (!formData.email.trim() || !formData.email.includes("@")) newErrors.email = true;
      if (!formData.phone.trim()) newErrors.phone = true;
      if (!formData.address.trim()) newErrors.address = true;
      if (!formData.city.trim()) newErrors.city = true;
      if (!formData.country.trim()) newErrors.country = true;
      if (!formData.zipCode.trim()) newErrors.zipCode = true;
    } else if (step === "payment" && paymentMethod === "credit_card") {
      if (!formData.cardNumber.trim() || formData.cardNumber.length < 16) newErrors.cardNumber = true;
      if (!formData.expiry.trim()) newErrors.expiry = true;
      if (!formData.cvc.trim() || formData.cvc.length < 3) newErrors.cvc = true;
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  /**
   * Handle input changes and update local state
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error when user starts typing
    if (errors[name]) {
      setErrors(prev => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }
  };

  /**
   * Handle form submission
   */
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validate()) return;

    if (step === "payment") {
      setIsSubmitting(true);
      // Simulate API call for order placement
      await new Promise(resolve => setTimeout(resolve, 2000));
      setIsSubmitting(false);
    }

    onNext({
      shippingAddress: {
        fullName: formData.fullName,
        email: formData.email,
        phone: formData.phone,
        address: formData.address,
        city: formData.city,
        country: formData.country,
        zipCode: formData.zipCode,
        notes: formData.notes
      },
      paymentMethod,
      shippingMethod
    });
  };

  return (
    <Card className="p-8 md:p-12 bg-surface-container/50 border-outline/10 backdrop-blur-md relative overflow-hidden group">
      {/* Decorative background glow */}
      <div className="absolute -top-24 -right-24 w-64 h-64 bg-primary/5 rounded-full blur-3xl opacity-50 group-hover:opacity-80 transition-opacity" />

      <form onSubmit={handleSubmit} className="relative z-10 space-y-10">
        <AnimatePresence mode="wait">
          {/* SHIPPING STEP */}
          {step === "shipping" && (
            <motion.div 
              key="shipping"
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              className="space-y-8"
            >
              <div className="flex items-center gap-3 mb-2">
                <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center border border-primary/20">
                  <Truck className="text-primary" size={20} />
                </div>
                <h3 className="text-headline-md font-bold text-text-main">{t.checkout.shipping}</h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
                <div className="space-y-2 md:col-span-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.full_name}</label>
                  <Input 
                    name="fullName" 
                    value={formData.fullName} 
                    onChange={handleChange} 
                    placeholder={t.checkout.full_name}
                    className={cn(
                      "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl",
                      errors.fullName && "border-error/50 ring-1 ring-error/20"
                    )}
                    required
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.email}</label>
                  <Input 
                    name="email" 
                    type="email" 
                    value={formData.email} 
                    onChange={handleChange} 
                    placeholder="commander@astroassist.ai"
                    className={cn(
                      "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl",
                      errors.email && "border-error/50 ring-1 ring-error/20"
                    )}
                    required
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.phone}</label>
                  <div className="relative">
                    <Input 
                      name="phone" 
                      type="tel"
                      value={formData.phone} 
                      onChange={handleChange} 
                      placeholder="+1 555 000 0000"
                      className={cn(
                        "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl pl-10",
                        errors.phone && "border-error/50 ring-1 ring-error/20"
                      )}
                      required
                    />
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-text-faint" size={16} />
                  </div>
                </div>

                <div className="space-y-2 md:col-span-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.address}</label>
                  <Input 
                    name="address" 
                    value={formData.address} 
                    onChange={handleChange} 
                    placeholder={t.checkout.address}
                    className={cn(
                      "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl",
                      errors.address && "border-error/50 ring-1 ring-error/20"
                    )}
                    required
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.city}</label>
                  <Input 
                    name="city" 
                    value={formData.city} 
                    onChange={handleChange} 
                    placeholder={t.checkout.city}
                    className={cn(
                      "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl",
                      errors.city && "border-error/50 ring-1 ring-error/20"
                    )}
                    required
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.country}</label>
                  <div className="relative">
                    <Input 
                      name="country" 
                      value={formData.country} 
                      onChange={handleChange} 
                      placeholder={t.checkout.country_placeholder}
                      className={cn(
                        "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl pl-10",
                        errors.country && "border-error/50 ring-1 ring-error/20"
                      )}
                      required
                    />
                    <Globe className="absolute left-3 top-1/2 -translate-y-1/2 text-text-faint" size={16} />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.zip_code}</label>
                  <Input 
                    name="zipCode" 
                    value={formData.zipCode} 
                    onChange={handleChange} 
                    placeholder={t.checkout.zip_code}
                    className={cn(
                      "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl",
                      errors.zipCode && "border-error/50 ring-1 ring-error/20"
                    )}
                    required
                  />
                </div>

                <div className="space-y-2 md:col-span-2">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.notes}</label>
                  <div className="relative">
                    <textarea 
                      name="notes" 
                      value={formData.notes} 
                      onChange={handleChange} 
                      placeholder="..."
                      className="w-full bg-background/40 border border-outline/10 focus:border-primary/50 rounded-xl p-4 min-h-[100px] text-body-sm text-text-main outline-none transition-colors"
                    />
                    <FileText className="absolute right-4 bottom-4 text-text-faint" size={16} />
                  </div>
                </div>

                {/* Shipping Method Selector */}
                <div className="md:col-span-2 pt-6">
                  <label className="text-label-sm text-text-muted uppercase tracking-wider block mb-4">{t.checkout.shipping_method}</label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <button 
                      type="button"
                      onClick={() => setShippingMethod("standard")}
                      className={cn(
                        "flex flex-col gap-2 p-5 rounded-2xl border-2 transition-all text-left group/opt",
                        shippingMethod === "standard" 
                          ? "border-primary bg-primary/10 text-text-main" 
                          : "border-outline/5 bg-surface-bright/5 text-text-soft hover:border-outline/20"
                      )}
                    >
                      <div className="flex items-center justify-between">
                        <span className="text-label-md font-bold uppercase tracking-widest">{t.checkout.standard_shipping}</span>
                        {shippingMethod === "standard" && <Check size={16} className="text-primary" />}
                      </div>
                      <span className="text-[11px] text-text-muted leading-tight group-hover/opt:text-text-soft">
                        {t.checkout.standard_shipping_desc}
                      </span>
                    </button>
                    <button 
                      type="button"
                      onClick={() => setShippingMethod("pickup")}
                      className={cn(
                        "flex flex-col gap-2 p-5 rounded-2xl border-2 transition-all text-left group/opt",
                        shippingMethod === "pickup" 
                          ? "border-primary bg-primary/10 text-text-main" 
                          : "border-outline/5 bg-surface-bright/5 text-text-soft hover:border-outline/20"
                      )}
                    >
                      <div className="flex items-center justify-between">
                        <span className="text-label-md font-bold uppercase tracking-widest">{t.checkout.pickup_shipping}</span>
                        {shippingMethod === "pickup" && <Check size={16} className="text-primary" />}
                      </div>
                      <span className="text-[11px] text-text-muted leading-tight group-hover/opt:text-text-soft">
                        {t.checkout.pickup_shipping_desc}
                      </span>
                    </button>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {/* PAYMENT STEP */}
          {step === "payment" && (
            <motion.div 
              key="payment"
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              className="space-y-8"
            >
              <div className="flex items-center gap-3 mb-2">
                <div className="w-10 h-10 rounded-xl bg-secondary/10 flex items-center justify-center border border-secondary/20">
                  <CreditCard className="text-secondary" size={20} />
                </div>
                <h3 className="text-headline-md font-bold text-text-main">{t.checkout.payment}</h3>
              </div>

              {/* Payment Method Selector */}
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
                <button 
                  type="button"
                  onClick={() => setPaymentMethod("credit_card")}
                  className={cn(
                    "flex flex-col items-center gap-3 p-5 rounded-2xl border-2 transition-all",
                    paymentMethod === "credit_card" 
                      ? "border-primary bg-primary/10 text-primary shadow-lg shadow-primary/10" 
                      : "border-outline/5 bg-surface-bright/10 text-text-muted hover:border-outline/20 hover:text-text-soft"
                  )}
                >
                  <CreditCard size={24} />
                  <span className="text-label-sm font-bold uppercase tracking-widest">{t.checkout.credit_card}</span>
                </button>
                <button 
                  type="button"
                  onClick={() => setPaymentMethod("paypal")}
                  className={cn(
                    "flex flex-col items-center gap-3 p-5 rounded-2xl border-2 transition-all",
                    paymentMethod === "paypal" 
                      ? "border-primary bg-primary/10 text-primary shadow-lg shadow-primary/10" 
                      : "border-outline/5 bg-surface-bright/10 text-text-muted hover:border-outline/20 hover:text-text-soft"
                  )}
                >
                  <Wallet size={24} />
                  <span className="text-label-sm font-bold uppercase tracking-widest">PayPal</span>
                </button>
                <button 
                  type="button"
                  onClick={() => setPaymentMethod("transfer")}
                  className={cn(
                    "flex flex-col items-center gap-3 p-5 rounded-2xl border-2 transition-all",
                    paymentMethod === "transfer" 
                      ? "border-primary bg-primary/10 text-primary shadow-lg shadow-primary/10" 
                      : "border-outline/5 bg-surface-bright/10 text-text-muted hover:border-outline/20 hover:text-text-soft"
                  )}
                >
                  <Landmark size={24} />
                  <span className="text-label-sm font-bold uppercase tracking-widest">{t.checkout.bank_transfer}</span>
                </button>
              </div>

              {paymentMethod === "credit_card" ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-6">
                  <div className="space-y-2 md:col-span-2">
                    <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.card_number}</label>
                    <div className="relative">
                      <Input 
                        name="cardNumber" 
                        value={formData.cardNumber} 
                        onChange={handleChange} 
                        placeholder="0000 0000 0000 0000"
                        className={cn(
                          "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl pl-12 font-mono tracking-widest",
                          errors.cardNumber && "border-error/50 ring-1 ring-error/20"
                        )}
                        required
                      />
                      <CreditCard className="absolute left-4 top-1/2 -translate-y-1/2 text-text-faint" size={18} />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.expiry}</label>
                    <Input 
                      name="expiry" 
                      value={formData.expiry} 
                      onChange={handleChange} 
                      placeholder="MM/YY"
                      className={cn(
                        "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl font-mono text-center",
                        errors.expiry && "border-error/50 ring-1 ring-error/20"
                      )}
                      required
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-label-sm text-text-muted uppercase tracking-wider">{t.checkout.cvc}</label>
                    <Input 
                      name="cvc" 
                      type="password"
                      maxLength={4}
                      value={formData.cvc} 
                      onChange={handleChange} 
                      placeholder="000"
                      className={cn(
                        "bg-background/40 border-outline/10 focus:border-primary/50 h-12 rounded-xl font-mono text-center",
                        errors.cvc && "border-error/50 ring-1 ring-error/20"
                      )}
                      required
                    />
                  </div>
                </div>
              ) : (
                <div className="p-8 rounded-2xl bg-primary/5 border border-primary/10 flex flex-col items-center text-center gap-4">
                  <div className="w-16 h-16 rounded-full bg-primary/10 flex items-center justify-center">
                    {paymentMethod === "paypal" ? <Wallet className="text-primary" size={32} /> : <Landmark className="text-primary" size={32} />}
                  </div>
                  <div>
                    <h4 className="text-title-sm font-bold text-text-main mb-2">
                      {paymentMethod === "paypal" ? "PayPal Express" : t.checkout.bank_transfer}
                    </h4>
                    <p className="text-body-sm text-text-muted max-w-sm">
                      {paymentMethod === "paypal" 
                        ? "Serás redirigido a PayPal para completar tu pago de forma segura." 
                        : "Los detalles de transferencia se enviarán a tu correo tras confirmar el pedido."}
                    </p>
                  </div>
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>

        {/* ACTIONS */}
        <div className="flex items-center justify-between pt-10 border-t border-outline/10">
          {step === "payment" ? (
            <Button 
              type="button" 
              variant="ghost" 
              onClick={onPrev}
              disabled={isSubmitting}
              className="h-14 px-8 text-text-soft hover:text-text-main group rounded-2xl"
            >
              <ArrowLeft className="mr-3 group-hover:-translate-x-1 transition-transform" size={20} />
              <span className="font-bold uppercase tracking-widest text-label-md">{t.checkout.back}</span>
            </Button>
          ) : (
            <div />
          )}

          <Button 
            type="submit" 
            size="lg"
            disabled={isSubmitting}
            className={cn(
              "h-14 px-10 rounded-2xl bg-primary hover:bg-primary-hover group shadow-xl shadow-primary/20",
              isSubmitting && "opacity-80 pointer-events-none"
            )}
          >
            {isSubmitting ? (
              <>
                <Loader2 className="mr-3 animate-spin" size={20} />
                <span className="font-bold uppercase tracking-widest text-label-md">{t.checkout.processing}</span>
              </>
            ) : (
              <>
                <span className="font-bold uppercase tracking-widest text-label-md">
                  {step === "shipping" ? t.checkout.continue : t.checkout.place_order}
                </span>
                <ArrowRight className="ml-3 group-hover:translate-x-1 transition-transform" size={20} />
              </>
            )}
          </Button>
        </div>
      </form>
    </Card>
  );
}

