                    </div>
                  </div>
                </div>
                
                <div className="mt-auto pt-6 border-t border-white/10">
                   <p className="text-body-sm text-text-faint leading-relaxed font-normal">
                     {t.modal_note}
                   </p>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </SectionContainer>
  );
}

